1	package cmd
2	
3	import (
4		"bufio"
5		"fmt"
6		"os"
7		"sort"
8		"strings"
9		"strconv"
10		"text/tabwriter"
11		"time"
12	
13		"github.com/sandcastle/cli/api"
14		"github.com/sandcastle/cli/internal/config"
15		"github.com/spf13/cobra"
16	)
17	
18	var (
19		sandboxImage         string
20		sandboxSnapshot      string
21		sandboxFromSnapshot  string
22		sandboxRestoreLayers string
23		sandboxTailscale     bool
24		sandboxNoConnect     bool
25		sandboxRemove        bool
26		sandboxHome          bool
27		sandboxData          string
28		sandboxNoVNC         bool
29		sandboxVNCGeometry   string
30		sandboxVNCDepth      int
31		sandboxNoDocker      bool
32		sandboxSMB           bool
33		listArchived         bool
34	)
35	
36	func init() {
37		rootCmd.AddCommand(createCmd)
38		rootCmd.AddCommand(listCmd)
39		rootCmd.AddCommand(deleteCmd)
40		deleteCmd.Flags().BoolVarP(&deleteForce, "force", "f", false, "Skip confirmation prompt")
41		rootCmd.AddCommand(startCmd)
42		rootCmd.AddCommand(stopCmd)
43		rootCmd.AddCommand(useCmd)
44		rootCmd.AddCommand(setCmd)
45		rootCmd.AddCommand(renameCmd)
46		rootCmd.AddCommand(archiveRestoreCmd)
47	
48		listCmd.Flags().BoolVar(&listArchived, "archived", false, "List archived (soft-deleted) sandboxes")
49	
50		createCmd.Flags().StringVar(&sandboxImage, "image", "ghcr.io/thieso2/sandcastle-sandbox:latest", "Container image")
51		createCmd.Flags().StringVar(&sandboxSnapshot, "snapshot", "", "Create from snapshot (legacy alias for --from-snapshot)")
52		createCmd.Flags().StringVar(&sandboxFromSnapshot, "from-snapshot", "", "Create from snapshot name (restores all available layers)")
53		createCmd.Flags().StringVar(&sandboxRestoreLayers, "restore-layers", "", "Comma-separated layers to restore: container,home,data (default: all)")
54		createCmd.Flags().BoolVar(&sandboxTailscale, "tailscale", false, "Connect to Tailscale network")
55		createCmd.Flags().BoolVarP(&sandboxNoConnect, "no-connect", "n", false, "Don't connect after creation")
56		createCmd.Flags().BoolVar(&sandboxRemove, "rm", false, "Delete sandbox on exit (env: SANDCASTLE_RM)")
57		createCmd.Flags().BoolVar(&sandboxHome, "home", false, "Mount persistent home directory (env: SANDCASTLE_HOME)")
58		createCmd.Flags().StringVar(&sandboxData, "data", "", "Mount user data directory (or subpath) to /persisted (env: SANDCASTLE_DATA)")
59		createCmd.Flags().Lookup("data").NoOptDefVal = "."
60		createCmd.Flags().BoolVar(&sandboxNoVNC, "no-vnc", false, "Disable VNC display server")
61		createCmd.Flags().StringVar(&sandboxVNCGeometry, "vnc-geometry", "", "VNC screen resolution (e.g. 1920x1080)")
62		createCmd.Flags().IntVar(&sandboxVNCDepth, "vnc-depth", 0, "VNC color depth: 8, 16, 24, or 32")
63		createCmd.Flags().BoolVar(&sandboxNoDocker, "no-docker", false, "Disable Docker daemon (DinD) inside sandbox")
64		createCmd.Flags().BoolVar(&sandboxSMB, "smb", false, "Enable SMB file sharing (requires Tailscale and SMB password set via 'sandcastle smb set-password')")
65	}
66	
67	var createCmd = &cobra.Command{
68		Use:     "create [name]",
69		Aliases: []string{"cr"},
70		Short:   "Create a new sandbox",
71		Long: `Create a new sandbox.
72	
73	If no name is provided, creates a temporary sandbox with an auto-generated name like "temp-<timestamp>".
74	
75	Environment variables can set defaults for commonly used flags:
76	  SANDCASTLE_HOME=1    equivalent to --home
77	  SANDCASTLE_DATA=.    equivalent to --data (value is the subpath, "." or "1" for root)
78	  SANDCASTLE_RM=1      equivalent to --rm
79	
80	Flags explicitly passed on the command line take precedence over environment variables.`,
81		Args: cobra.MaximumNArgs(1),
82		PreRun: func(cmd *cobra.Command, args []string) {
83			// Priority: explicit flag > env var > config preference
84			cfg, _ := config.Load()
85			prefs := cfg.LoadPreferences()
86	
87			if !cmd.Flags().Changed("home") {
88				if prefs.MountHome != nil && *prefs.MountHome {
89					sandboxHome = true
90				}
91			}
92			if !cmd.Flags().Changed("rm") && envTruthy("SANDCASTLE_RM") {
93				sandboxRemove = true
94			}
95			if !cmd.Flags().Changed("data") {
96				if prefs.DataPath != "" {
97					sandboxData = prefs.DataPath
98				}
99			}
100			if !cmd.Flags().Changed("no-vnc") {
101				if prefs.VNC != nil && !*prefs.VNC {
102					sandboxNoVNC = true
103				}
104			}
105			if !cmd.Flags().Changed("no-docker") {
106				if prefs.Docker != nil && !*prefs.Docker {
107					sandboxNoDocker = true
108				}
109			}
110		},
111		RunE: func(cmd *cobra.Command, args []string) error {
112			client, err := api.NewClient()
113			if err != nil {
114				return err
115			}
116			printServer(client)
117	
118			// Auto-generate name if not provided
119			var name string
120			autoGenerated := false
121			if len(args) == 0 {
122				name = fmt.Sprintf("temp-%d", time.Now().Unix())
123				autoGenerated = true
124				// Auto-generated sandboxes are temporary by default
125				if !cmd.Flags().Changed("rm") {
126					sandboxRemove = true
127				}
128			} else {
129				name = args[0]
130			}
131	
132			// Resolve snapshot flags: --from-snapshot takes precedence over --snapshot
133			fromSnap := sandboxFromSnapshot
134			if fromSnap == "" {
135				fromSnap = sandboxSnapshot
136			}
137	
138			var restoreLayers []string
139			if sandboxRestoreLayers != "" {
140				for _, l := range strings.Split(sandboxRestoreLayers, ",") {
141					restoreLayers = append(restoreLayers, strings.TrimSpace(l))
142				}
143			}
144	
145			sandbox, err := client.CreateSandbox(api.CreateSandboxRequest{
146				Name:          name,
147				Image:         sandboxImage,
148				FromSnapshot:  fromSnap,
149				RestoreLayers: restoreLayers,
150				Tailscale:     sandboxTailscale,
151				MountHome:     sandboxHome,
152				DataPath:      sandboxData,
153				Temporary:     sandboxRemove,
154				VNCEnabled:    !sandboxNoVNC,
155				VNCGeometry:   sandboxVNCGeometry,
156				VNCDepth:      sandboxVNCDepth,
157				DockerEnabled: !sandboxNoDocker,
158				SMBEnabled:    sandboxSMB,
159			})
160			if err != nil {
161				return err
162			}
163	
164			if autoGenerated {
165				fmt.Printf("Sandbox %q created (auto-generated name).\n", sandbox.Name)
166			} else {
167				fmt.Printf("Sandbox %q created.\n", sandbox.Name)
168			}
169	
170			// Print active options (use local flags — they reflect what was actually requested)
171			if sandboxHome || sandboxData != "" || sandbox.Tailscale || sandboxRemove || fromSnap != "" || sandboxNoVNC || sandboxVNCGeometry != "" || sandboxVNCDepth != 0 || sandboxNoDocker || sandboxSMB {
172				if sandboxHome {
173					fmt.Println("  Home:      mounted (~/ persisted)")
174				}
175				if sandboxData != "" {
176					label := sandboxData
177					if label == "." {
178						label = "user data root"
179					}
180					fmt.Printf("  Data:      mounted (%s → /persisted)\n", label)
181				}
182				if sandbox.Tailscale {
183					fmt.Println("  Tailscale: enabled")
184				}
185				if sandboxRemove {
186					fmt.Println("  Cleanup:   auto-remove on exit")
187				}
188				if fromSnap != "" {
189					fmt.Printf("  Snapshot:  restored from %q\n", fromSnap)
190				}
191				if sandboxNoDocker {
192					fmt.Println("  Docker:    disabled")
193				}
194				if sandboxNoVNC {
195					fmt.Println("  VNC:       disabled")
196				} else if sandboxVNCGeometry != "" || sandboxVNCDepth != 0 {
197					geom := sandbox.VNCGeometry
198					if geom == "" {
199						geom = "1280x900"
200					}
201					depth := sandbox.VNCDepth
202					if depth == 0 {
203						depth = 24
204					}
205					fmt.Printf("  VNC:       %s @ %d-bit\n", geom, depth)
206				}
207				if sandboxSMB {
208					fmt.Println("  SMB:       enabled")
209				}
210			}
211	
212			if sandboxNoConnect {
213				return nil
214			}
215	
216			info, err := client.ConnectInfo(sandbox.ID)
217			if err != nil {
218				return err
219			}
220	
221			if os.Getenv("VERBOSE") == "1" {
222				fmt.Fprintf(os.Stderr, "\033[2m[verbose] Connection info: host=%s port=%d user=%s\033[0m\n", info.Host, info.Port, info.User)
223				if info.TailscaleIP != "" {
224					fmt.Fprintf(os.Stderr, "\033[2m[verbose] Tailscale IP (Tailscale): %s\033[0m\n", info.TailscaleIP)
225				}
226			}
227	
228			if err := checkHostReachable(info.Host, info.Port); err != nil {
229				return err
230			}
231	
232			if err := waitForSSH(info.Host, info.Port); err != nil {
233				return err
234			}
235	
236			cfg, loadErr := config.Load()
237			if loadErr != nil {
238				return loadErr
239			}
240			prefs := cfg.LoadPreferences()
241	
242			var remoteCmd string
243			if *prefs.UseTmux {
244				remoteCmd = tmuxCmd
245			}
246	
247			var sshErr error
248			if pickProtocol(cfg, info.Host, info.Port, info.User, prefs.SSHExtraArgs) == "mosh" {
249				fmt.Fprintf(os.Stderr, "\033[33mWarning:\033[0m mosh does not support SSH agent forwarding. Use --mosh=no if you need ssh-add keys inside the sandbox.\n")
250				sshErr = moshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs, nil)
251			} else {
252				sshErr = sshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs, nil)
253			}
254	
255			if sandboxRemove {
256				// Re-fetch to check if user toggled to "keep" during the session
257				current, fetchErr := client.GetSandbox(sandbox.ID)
258				if fetchErr == nil && !current.Temporary {
259					fmt.Printf("Sandbox %q was set to keep — skipping removal.\n", sandbox.Name)
260				} else {
261					fmt.Printf("Removing sandbox %q...\n", sandbox.Name)
262					if err := client.DestroySandbox(sandbox.ID); err != nil {
263						fmt.Fprintf(os.Stderr, "Warning: failed to delete sandbox: %v\n", err)
264					} else {
265						fmt.Printf("Sandbox %q deleted.\n", sandbox.Name)
266					}
267				}
268			}
269	
270			return sshErr
271		},
272	}
273	
274	var listCmd = &cobra.Command{
275		Use:     "list",
276		Aliases: []string{"ls"},
277		Short:   "List all sandboxes",
278		RunE: func(cmd *cobra.Command, args []string) error {
279			client, err := api.NewClient()
280			if err != nil {
281				return err
282			}
283			printServer(client)
284	
285			if listArchived {
286				sandboxes, err := client.ListArchivedSandboxes()
287				if err != nil {
288					return err
289				}
290				if len(sandboxes) == 0 {
291					fmt.Println("No archived sandboxes.")
292					return nil
293				}
294				w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
295				fmt.Fprintln(w, "ID\tNAME\tARCHIVED\tCREATED\tIMAGE")
296				for _, s := range sandboxes {
297					archivedAt := ""
298					if s.ArchivedAt != nil {
299						archivedAt = s.ArchivedAt.Local().Format("2006-01-02 15:04")
300					}
301					created := s.CreatedAt.Local().Format("2006-01-02 15:04")
302					fmt.Fprintf(w, "%d\t%s\t%s\t%s\t%s\n", s.ID, s.Name, archivedAt, created, s.Image)
303				}
304				w.Flush()
305				return nil
306			}
307	
308			sandboxes, err := client.ListSandboxes()
309			if err != nil {
310				return err
311			}
312	
313			if len(sandboxes) == 0 {
314				fmt.Println("No sandboxes.")
315				return nil
316			}
317	
318			hasRoute := false
319			for _, s := range sandboxes {
320				if len(s.Routes) > 0 {
321					hasRoute = true
322					break
323				}
324			}
325	
326			w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
327			if hasRoute {
328				fmt.Fprintln(w, "NAME\tSTATUS\tCREATED\tROUTE\tTAILSCALE IP\tIMAGE AGE")
329			} else {
330				fmt.Fprintln(w, "NAME\tSTATUS\tCREATED\tTAILSCALE IP\tIMAGE AGE")
331			}
332			for _, s := range sandboxes {
333				name := s.Name
334				if s.Temporary {
335					name += " (temp)"
336				}
337				tsIP := ""
338				if s.TailscaleIP != "" {
339					tsIP = s.TailscaleIP
340				}
341				created  := s.CreatedAt.Local().Format("2006-01-02 15:04")
342				imageAge := formatImageAge(s.ImageBuiltAt)
343				if hasRoute {
344					route := ""
345					if len(s.Routes) > 0 {
346						parts := make([]string, len(s.Routes))
347						for i, r := range s.Routes {
348							parts[i] = fmt.Sprintf("%s (:%d)", r.URL, r.Port)
349						}
350						route = strings.Join(parts, ", ")
351					}
352					fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\t%s\n", name, s.Status, created, route, tsIP, imageAge)
353				} else {
354					fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\n", name, s.Status, created, tsIP, imageAge)
355				}
356			}
357			w.Flush()
358			return nil
359		},
360	}
361	
362	var archiveRestoreCmd = &cobra.Command{
363		Use:   "unarchive <id>",
364		Short: "Restore an archived sandbox",
365		Long: `Restore an archived sandbox by its ID, recreating the container from the preserved volume.
366	The sandbox is restored in running state. Use 'sandcastle list --archived' to see IDs.`,
367		Args: cobra.ExactArgs(1),
368		RunE: func(cmd *cobra.Command, args []string) error {
369			id, err := strconv.Atoi(args[0])
370			if err != nil {
371				return fmt.Errorf("invalid sandbox ID %q: must be a number (use 'sandcastle list --archived' to see IDs)", args[0])
372			}
373	
374			client, err := api.NewClient()
375			if err != nil {
376				return err
377			}
378			printServer(client)
379	
380			sandbox, err := client.ArchiveRestoreSandbox(id)
381			if err != nil {
382				return err
383			}
384	
385			fmt.Printf("Sandbox %q restored (status: %s).\n", sandbox.Name, sandbox.Status)
386			return nil
387		},
388	}
389	
390	var deleteForce bool
391	
392	var deleteCmd = &cobra.Command{
393		Use:     "delete <name>",
394		Aliases: []string{"rm", "d"},
395		Short:   "Delete a sandbox",
396		Args:  cobra.ExactArgs(1),
397		RunE: func(cmd *cobra.Command, args []string) error {
