482	
483	var useCmd = &cobra.Command{
484		Use:   "use [name]",
485		Short: "Show or set active server/sandbox",
486		Long: `Without arguments, shows the current server and active sandbox.
487	With an argument, switches the active server or sandbox.
488	
489	Examples:
490	  sandcastle use                  # Show current server and sandbox
491	  sandcastle use my-sandbox       # Set active sandbox
492	  sandcastle use prod             # Switch to server "prod" (if configured)`,
493		Args: cobra.MaximumNArgs(1),
494		RunE: func(cmd *cobra.Command, args []string) error {
495			cfg, err := config.Load()
496			if err != nil {
497				return err
498			}
499	
500			// No args: list all servers, highlight active
501			if len(args) == 0 {
502				if len(cfg.Servers) == 0 {
503					fmt.Println("No servers configured — run: sandcastle login <url>")
504					return nil
505				}
506	
507				aliases := make([]string, 0, len(cfg.Servers))
508				for alias := range cfg.Servers {
509					aliases = append(aliases, alias)
510				}
511				sort.Strings(aliases)
512	
513				for _, alias := range aliases {
514					srv := cfg.Servers[alias]
515					if alias == cfg.CurrentServer {
516						fmt.Printf("  \033[1m* %-16s\033[0m %s\n", alias, srv.URL)
517					} else {
518						fmt.Printf("    %-16s %s\n", alias, srv.URL)
519					}
520				}
521	
522				return nil
523			}
524	
525			name := args[0]
526	
527			// Check if name matches a server alias or URL
528			if _, ok := cfg.Servers[name]; ok {
529				cfg.CurrentServer = name
530				if err := config.Save(cfg); err != nil {
531					return err
532				}
533				fmt.Printf("Switched to server %s (%s)\n", name, cfg.Servers[name].URL)
534				return nil
535			}
536	
537			// Try matching by URL
538			for alias, srv := range cfg.Servers {
539				if srv.URL == strings.TrimRight(name, "/") {
540					cfg.CurrentServer = alias
541					if err := config.Save(cfg); err != nil {
542						return err
543					}
544					fmt.Printf("Switched to server %s (%s)\n", alias, srv.URL)
545					return nil
546				}
547			}
548	
549			return fmt.Errorf("server %q not found — run: sandcastle use", name)
550		},
551	}
552	
553	var setCmd = &cobra.Command{
554		Use:   "set <name> <temp|keep>",
555		Short: "Toggle sandbox between temporary and kept",
556		Long: `Toggle a sandbox between temporary (auto-remove on exit) and kept.
557	
558	  temp   Mark as temporary — will be removed when the CLI session exits
559	  keep   Mark as kept — will not be auto-removed`,
560		Args: cobra.ExactArgs(2),
561		RunE: func(cmd *cobra.Command, args []string) error {
562			client, err := api.NewClient()
563			if err != nil {
564				return err
565			}
566			printServer(client)
567	
568			sandbox, err := findSandboxByName(client, args[0])
569			if err != nil {
570				return err
571			}
572	
573			mode := strings.ToLower(args[1])
574			var temp bool
575			switch mode {
576			case "temp":
577				temp = true
578			case "keep":
579				temp = false
580			default:
581				return fmt.Errorf("unknown mode %q: use \"temp\" or \"keep\"", args[1])
582			}
583	
584			sandbox, err = client.UpdateSandbox(sandbox.ID, api.UpdateSandboxRequest{Temporary: &temp})
585			if err != nil {
586				return err
587			}
588	
589			if temp {
590				fmt.Printf("Sandbox %q set to temporary (will be removed on exit).\n", sandbox.Name)
591			} else {
592				fmt.Printf("Sandbox %q set to keep (will not be removed on exit).\n", sandbox.Name)
593			}
594			return nil
595		},
596	}
597	
598	var renameCmd = &cobra.Command{
599		Use:     "rename <name> <new-name>",
600		Aliases: []string{"mv"},
601		Short:   "Rename a sandbox",
602		Args:    cobra.ExactArgs(2),
603		RunE: func(cmd *cobra.Command, args []string) error {
604			client, err := api.NewClient()
605			if err != nil {
606				return err
607			}
608			printServer(client)
609	
610			sandbox, err := findSandboxByName(client, args[0])
611			if err != nil {
612				return err
613			}
614	
615			newName := args[1]
616			sandbox, err = client.UpdateSandbox(sandbox.ID, api.UpdateSandboxRequest{Name: &newName})
617			if err != nil {
618				return err
619			}
620	
621			fmt.Printf("Sandbox renamed to %q.\n", sandbox.Name)
622			return nil
623		},
624	}
625	
626	// formatImageAge returns a human-readable image age string (e.g. "2h ago", "3d ago").
627	// Returns "-" when the build timestamp is not available.
628	func formatImageAge(builtAt *time.Time) string {
629		if builtAt == nil {
630			return "-"
631		}
632		d := time.Since(*builtAt)
633		switch {
634		case d < time.Minute:
635			return "just now"
636		case d < time.Hour:
637			return fmt.Sprintf("%dm ago", int(d.Minutes()))
638		case d < 24*time.Hour:
639			return fmt.Sprintf("%dh ago", int(d.Hours()))
640		default:
641			return fmt.Sprintf("%dd ago", int(d.Hours()/24))
642		}
643	}
644	
645	func envTruthy(key string) bool {
646		v := strings.ToLower(os.Getenv(key))
647		return v == "1" || v == "true" || v == "yes"
648	}
649	
650	func findSandboxByName(client *api.Client, name string) (*api.Sandbox, error) {
651		sandboxes, err := client.ListSandboxes()
652		if err != nil {
653			return nil, err
654		}
655		for _, s := range sandboxes {
656			if s.Name == name {
657				return &s, nil
658			}
659		}
660		return nil, fmt.Errorf("sandbox %q not found", name)
661	}
