1	package api
2	
3	import (
4		"bytes"
5		"crypto/tls"
6		"encoding/json"
7		"fmt"
8		"io"
9		"net/http"
10		"os"
11		"strings"
12	
13		"github.com/sandcastle/cli/internal/config"
14	)
15	
16	func verbose() bool {
17		// Check both VERBOSE and SANDCASTLE_VERBOSE
18		v := strings.ToLower(os.Getenv("VERBOSE"))
19		if v == "" {
20			v = strings.ToLower(os.Getenv("SANDCASTLE_VERBOSE"))
21		}
22		return v == "1" || v == "true"
23	}
24	
25	func logVerbose(format string, args ...any) {
26		if verbose() {
27			fmt.Fprintf(os.Stderr, "\033[2m"+format+"\033[0m\n", args...)
28		}
29	}
30	
31	type Client struct {
32		BaseURL     string
33		Token       string
34		ServerAlias string
35		HTTPClient  *http.Client
36	}
37	
38	func newHTTPClient(insecure bool) *http.Client {
39		if insecure {
40			return &http.Client{
41				Transport: &http.Transport{
42					TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
43				},
44			}
45		}
46		return &http.Client{}
47	}
48	
49	func NewClient() (*Client, error) {
50		cfg, err := config.Load()
51		if err != nil {
52			return nil, err
53		}
54	
55		// SANDCASTLE_HOST overrides the active server — accepts a server alias or URL.
56		if host := os.Getenv("SANDCASTLE_HOST"); host != "" {
57			// 1. Alias match
58			if srv, ok := cfg.Servers[host]; ok {
59				logVerbose("server (SANDCASTLE_HOST alias): %s (%s)", host, srv.URL)
60				return &Client{
61					BaseURL:     srv.URL,
62					Token:       srv.Token,
63					ServerAlias: host,
64					HTTPClient:  newHTTPClient(srv.Insecure),
65				}, nil
66			}
67			// 2. URL match — reuse stored token for that server
68			normalized := strings.TrimRight(host, "/")
69			for alias, srv := range cfg.Servers {
70				if strings.TrimRight(srv.URL, "/") == normalized {
71					logVerbose("server (SANDCASTLE_HOST url): %s (%s)", alias, normalized)
72					return &Client{
73						BaseURL:     normalized,
74						Token:       srv.Token,
75						ServerAlias: alias,
76						HTTPClient:  newHTTPClient(srv.Insecure),
77					}, nil
78				}
79			}
80			// 3. Unknown URL — use without auth
81			logVerbose("server (SANDCASTLE_HOST, unauthenticated): %s", normalized)
82			return &Client{
83				BaseURL:    normalized,
84				HTTPClient: newHTTPClient(false),
85			}, nil
86		}
87	
88		srv, err := cfg.CurrentServerConfig()
89		if err != nil {
90			return nil, err
91		}
92		logVerbose("server: %s (%s)", cfg.CurrentServer, srv.URL)
93		return &Client{
94			BaseURL:     srv.URL,
95			Token:       srv.Token,
96			ServerAlias: cfg.CurrentServer,
97			HTTPClient:  newHTTPClient(srv.Insecure),
98		}, nil
99	}
100	
101	func NewClientWithToken(baseURL, token string, insecure bool) *Client {
102		return &Client{
103			BaseURL:    baseURL,
104			Token:      token,
105			HTTPClient: newHTTPClient(insecure),
106		}
107	}
108	
109	func (c *Client) do(method, path string, body any, result any) error {
110		var bodyReader io.Reader
111		var reqData []byte
112		if body != nil {
113			var err error
114			reqData, err = json.Marshal(body)
115			if err != nil {
116				return fmt.Errorf("marshaling request: %w", err)
117			}
118			bodyReader = bytes.NewReader(reqData)
119		}
120	
121		logVerbose("→ %s %s%s", method, c.BaseURL, path)
122		if len(reqData) > 0 {
123			logVerbose("  request: %s", string(reqData))
124		}
125	
126		req, err := http.NewRequest(method, c.BaseURL+path, bodyReader)
127		if err != nil {
128			return fmt.Errorf("creating request: %w", err)
129		}
130	
131		req.Header.Set("Content-Type", "application/json")
132		if c.Token != "" {
133			req.Header.Set("Authorization", "Bearer "+c.Token)
134		}
135	
136		resp, err := c.HTTPClient.Do(req)
137		if err != nil {
138			return fmt.Errorf("request failed: %w", err)
139		}
140		defer resp.Body.Close()
141	
142		respBody, err := io.ReadAll(resp.Body)
143		if err != nil {
144			return fmt.Errorf("reading response: %w", err)
145		}
146	
147		logVerbose("← %d (%d bytes)", resp.StatusCode, len(respBody))
148		if len(respBody) > 0 {
149			logVerbose("  response: %s", string(respBody))
150		}
151	
152		if resp.StatusCode >= 400 {
153			var apiErr APIError
154			if json.Unmarshal(respBody, &apiErr) == nil && apiErr.Error != "" {
155				return fmt.Errorf("API error (%d): %s", resp.StatusCode, apiErr.Error)
156			}
157			return fmt.Errorf("API error (%d): %s", resp.StatusCode, string(respBody))
158		}
159	
160		if result != nil {
161			if err := json.Unmarshal(respBody, result); err != nil {
162				return fmt.Errorf("parsing response: %w", err)
163			}
164		}
165		return nil
166	}
167	
168	// doWithStatus is like do but returns the HTTP status code along with the response body.
169	func (c *Client) doWithStatus(method, path string, body any) (int, []byte, error) {
170		var bodyReader io.Reader
171		var reqData []byte
172		if body != nil {
173			var err error
174			reqData, err = json.Marshal(body)
175			if err != nil {
176				return 0, nil, fmt.Errorf("marshaling request: %w", err)
177			}
178			bodyReader = bytes.NewReader(reqData)
179		}
180	
181		logVerbose("→ %s %s%s", method, c.BaseURL, path)
182		if len(reqData) > 0 {
183			logVerbose("  request: %s", string(reqData))
184		}
185	
186		req, err := http.NewRequest(method, c.BaseURL+path, bodyReader)
187		if err != nil {
188			return 0, nil, fmt.Errorf("creating request: %w", err)
189		}
190	
191		req.Header.Set("Content-Type", "application/json")
192		if c.Token != "" {
193			req.Header.Set("Authorization", "Bearer "+c.Token)
194		}
195	
196		resp, err := c.HTTPClient.Do(req)
197		if err != nil {
198			return 0, nil, fmt.Errorf("request failed: %w", err)
199		}
200		defer resp.Body.Close()
201	
202		respBody, err := io.ReadAll(resp.Body)
203		if err != nil {
204			return 0, nil, fmt.Errorf("reading response: %w", err)
205		}
206	
207		logVerbose("← %d (%d bytes)", resp.StatusCode, len(respBody))
208		if len(respBody) > 0 {
209			logVerbose("  response: %s", string(respBody))
210		}
211	
212		return resp.StatusCode, respBody, nil
213	}
214	
215	// Device Auth
216	
217	func (c *Client) RequestDeviceCode(clientName string) (*DeviceCodeResponse, error) {
218		var resp DeviceCodeResponse
219		err := c.do("POST", "/api/auth/device_code", DeviceCodeRequest{ClientName: clientName}, &resp)
220		return &resp, err
221	}
222	
223	func (c *Client) PollDeviceToken(deviceCode string) (token string, pending bool, err error) {
224		status, body, err := c.doWithStatus("POST", "/api/auth/device_token", DeviceTokenRequest{DeviceCode: deviceCode})
225		if err != nil {
226			return "", false, err
227		}
228	
229		switch status {
230		case 200:
231			var resp DeviceTokenResponse
232			if err := json.Unmarshal(body, &resp); err != nil {
233				return "", false, fmt.Errorf("parsing response: %w", err)
234			}
235			return resp.Token, false, nil
236		case 428: // Precondition Required — authorization_pending
237			return "", true, nil
