216				return m, tea.Batch(m.spinner.Tick, loadRoutes(m.client, m.routeSandbox.ID))
217			}
218			return m, tea.Batch(m.spinner.Tick, loadSandboxes(m.client))
219		}
220	
221		switch m.view {
222		case viewSandboxes:
