241			case key.Matches(msg, key.NewBinding(key.WithKeys("q", "ctrl+c"))):
242				return m, tea.Quit
243			case key.Matches(msg, key.NewBinding(key.WithKeys("up", "k"))):
244				if m.cursor > 0 {
245					m.cursor--
246				}
247			case key.Matches(msg, key.NewBinding(key.WithKeys("down", "j"))):
248				if m.cursor < len(m.sandboxes)-1 {
249					m.cursor++
