316	func (m tuiModel) updateRoutes(msg tea.Msg) (tea.Model, tea.Cmd) {
317		switch msg := msg.(type) {
318		case tea.KeyMsg:
319			m.feedback = ""
320			switch {
321			case key.Matches(msg, key.NewBinding(key.WithKeys("q", "esc"))):
322				m.view = viewSandboxes
323				m.routes = nil
324				m.routeSandbox = nil
325			case key.Matches(msg, key.NewBinding(key.WithKeys("ctrl+c"))):
326				return m, tea.Quit
327			case key.Matches(msg, key.NewBinding(key.WithKeys("up", "k"))):
328				if m.routeCursor > 0 {
329					m.routeCursor--
330				}
331			case key.Matches(msg, key.NewBinding(key.WithKeys("down", "j"))):
332				if m.routeCursor < len(m.routes)-1 {
333					m.routeCursor++
334				}
335			case key.Matches(msg, key.NewBinding(key.WithKeys("a"))):
336				m.view = viewAddRoute
337				m.routeFocusIdx = 0
338				m.routeInputs[0].SetValue("")
339				m.routeInputs[1].SetValue("")
340				m.routeInputs[0].Focus()
341				m.routeInputs[1].Blur()
342				return m, m.routeInputs[0].Cursor.BlinkCmd()
343			case key.Matches(msg, key.NewBinding(key.WithKeys("d"))):
344				if len(m.routes) > 0 {
345					r := m.routes[m.routeCursor]
346					sbID := m.routeSandbox.ID
347					m.loading = true
348					return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
349						err := m.client.RemoveRouteByID(sbID, r.ID)
350						return fmt.Sprintf("Route #%d removed", r.ID), err
351					}))
352				}
353			case key.Matches(msg, key.NewBinding(key.WithKeys("R"))):
354				if m.routeSandbox != nil {
355					m.loading = true
356					return m, tea.Batch(m.spinner.Tick, loadRoutes(m.client, m.routeSandbox.ID))
357				}
358			}
359		}
360		return m, nil
361	}
362	
363	func (m tuiModel) updateCreate(msg tea.Msg) (tea.Model, tea.Cmd) {
364		switch msg := msg.(type) {
365		case tea.KeyMsg:
366			switch msg.Type {
367			case tea.KeyEsc:
368				m.view = viewSandboxes
369				return m, nil
370			case tea.KeyCtrlC:
371				return m, tea.Quit
372			case tea.KeyEnter:
373				name := strings.TrimSpace(m.createInput.Value())
374				if name == "" {
375					name = fmt.Sprintf("temp-%d", time.Now().Unix())
376				}
377				m.view = viewSandboxes
378				m.loading = true
379				return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
380					sb, err := m.client.CreateSandbox(api.CreateSandboxRequest{
381						Name:          name,
382						Image:         "ghcr.io/thieso2/sandcastle-sandbox:latest",
383						VNCEnabled:    true,
384						DockerEnabled: true,
385					})
386					if err != nil {
387						return "", err
388					}
389					return fmt.Sprintf("%q created", sb.Name), nil
390				}))
391			}
392		}
393		var cmd tea.Cmd
394		m.createInput, cmd = m.createInput.Update(msg)
395		return m, cmd
396	}
397	
398	func (m tuiModel) updateAddRoute(msg tea.Msg) (tea.Model, tea.Cmd) {
399		switch msg := msg.(type) {
400		case tea.KeyMsg:
401			switch msg.Type {
402			case tea.KeyEsc:
403				m.view = viewRoutes
404				return m, nil
405			case tea.KeyCtrlC:
406				return m, tea.Quit
407			case tea.KeyTab, tea.KeyShiftTab:
408				m.routeFocusIdx = (m.routeFocusIdx + 1) % 2
409				for i := range m.routeInputs {
410					if i == m.routeFocusIdx {
411						m.routeInputs[i].Focus()
412					} else {
413						m.routeInputs[i].Blur()
414					}
415				}
416				return m, m.routeInputs[m.routeFocusIdx].Cursor.BlinkCmd()
417			case tea.KeyEnter:
418				domain := strings.TrimSpace(m.routeInputs[0].Value())
419				portStr := strings.TrimSpace(m.routeInputs[1].Value())
420				if domain == "" {
421					m.feedback = "domain is required"
422					m.feedErr = true
423					return m, nil
424				}
425				port := 8080
426				if portStr != "" {
427					n := 0
428					for _, ch := range portStr {
429						if ch < '0' || ch > '9' {
430							m.feedback = "invalid port"
431							m.feedErr = true
432							return m, nil
433						}
434						n = n*10 + int(ch-'0')
435					}
436					port = n
437				}
438				sbID := m.routeSandbox.ID
439				m.view = viewRoutes
440				m.loading = true
441				return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
442					r, err := m.client.AddRoute(sbID, api.RouteRequest{
443						Domain: domain,
444						Port:   port,
445						Mode:   "http",
446					})
447					if err != nil {
448						return "", err
449					}
450					return fmt.Sprintf("Route added: %s → :%d", r.Domain, r.Port), nil
451				}))
452			}
453		}
454	
455		var cmd tea.Cmd
456		m.routeInputs[m.routeFocusIdx], cmd = m.routeInputs[m.routeFocusIdx].Update(msg)
457		return m, cmd
458	}
459	
460	func (m tuiModel) updateConfirmDelete(msg tea.Msg) (tea.Model, tea.Cmd) {
461		switch msg := msg.(type) {
462		case tea.KeyMsg:
463			switch {
464			case key.Matches(msg, key.NewBinding(key.WithKeys("y", "Y"))):
465				id := m.deleteID
466				name := m.deleteTarget
467				m.loading = true
468				return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
469					err := m.client.DestroySandbox(id)
470					return fmt.Sprintf("%q destroyed", name), err
471				}))
472			default:
473				m.view = viewSandboxes
474				m.feedback = "cancelled"
475				m.feedErr = false
476			}
477		}
478		return m, nil
479	}
480	
481	// ---------- view ----------
482	
483	func (m tuiModel) View() string {
484		var b strings.Builder
485	
486		title := titleStyle.Render("  Sandcastle")
487		if m.client.ServerAlias != "" {
488			title += helpStyle.Render(fmt.Sprintf("  %s", m.client.ServerAlias))
489		}
490		b.WriteString(title + "\n\n")
491	
492		switch m.view {
493		case viewSandboxes:
494			m.viewSandboxes(&b)
495		case viewRoutes:
496			m.viewRoutes(&b)
497		case viewCreateSandbox:
498			m.viewCreate(&b)
499		case viewAddRoute:
500			m.viewAddRoute(&b)
501		case viewConfirmDelete:
502			m.viewConfirmDelete(&b)
503		}
504	
505		// Feedback
506		if m.feedback != "" {
507			b.WriteString("\n")
508			if m.feedErr {
509				b.WriteString(errStyle.Render("  " + m.feedback))
510			} else {
511				b.WriteString(okStyle.Render("  " + m.feedback))
512			}
513			b.WriteString("\n")
514		}
515	
516		return b.String()
517	}
518	
519	func (m tuiModel) viewSandboxes(b *strings.Builder) {
520		if m.loading && len(m.sandboxes) == 0 {
521			b.WriteString("  " + m.spinner.View() + " Loading sandboxes...\n")
522			b.WriteString("\n" + helpStyle.Render("  q quit"))
523			return
524		}
525	
526		if len(m.sandboxes) == 0 {
527			b.WriteString("  No sandboxes. Press c to create one.\n")
528		} else {
529			// Header
530			b.WriteString(headerStyle.Render(fmt.Sprintf("  %-22s %-10s %-18s %s", "NAME", "STATUS", "CREATED", "ROUTE")) + "\n")
531	
532			for i, sb := range m.sandboxes {
533				name := sb.Name
534				if sb.Temporary {
535					name += " ~"
536				}
537				if len(name) > 22 {
538					name = name[:21] + "…"
539				}
540	
541				st := statusStopped.Render(sb.Status)
542				if sb.Status == "running" {
543					st = statusRunning.Render(sb.Status)
544				}
545	
546				created := sb.CreatedAt.Local().Format("Jan 02 15:04")
547	
548				route := ""
549				if len(sb.Routes) > 0 {
550					parts := make([]string, 0, len(sb.Routes))
551					for _, r := range sb.Routes {
552						if r.Mode == "tcp" {
553							parts = append(parts, fmt.Sprintf("tcp/:%d", r.PublicPort))
554						} else {
555							parts = append(parts, r.Domain)
556						}
557					}
558					route = strings.Join(parts, ", ")
559					if len(route) > 30 {
560						route = route[:29] + "…"
561					}
562				}
563	
564				line := fmt.Sprintf("  %-22s %-10s %-18s %s", name, st, created, route)
565				if i == m.cursor {
566					// Re-render with selection styling — pad to width
567					padded := fmt.Sprintf("  %-22s %-20s %-18s %-30s", name, sb.Status, created, route)
568					line = selectedStyle.Render(padded)
569				}
570				b.WriteString(line + "\n")
571			}
572		}
573	
574		if m.loading {
575			b.WriteString("\n  " + m.spinner.View() + "\n")
576		}
577	
578		b.WriteString("\n")
579		b.WriteString(helpStyle.Render("  enter connect  c create  s start  x stop  d destroy  r routes  R refresh  q quit"))
580		b.WriteString("\n")
581	}
582	
583	func (m tuiModel) viewRoutes(b *strings.Builder) {
584		b.WriteString(headerStyle.Render(fmt.Sprintf("  Routes for %s", m.routeSandbox.Name)) + "\n\n")
585	
586		if m.loading {
587			b.WriteString("  " + m.spinner.View() + " Loading routes...\n")
588			b.WriteString("\n" + helpStyle.Render("  esc back  q quit"))
589			return
590		}
591	
592		if len(m.routes) == 0 {
593			b.WriteString("  No routes. Press a to add one.\n")
594		} else {
595			b.WriteString(headerStyle.Render(fmt.Sprintf("  %-6s %-6s %-30s %-8s %s", "ID", "MODE", "DOMAIN / PUBLIC PORT", "PORT", "URL")) + "\n")
596			for i, r := range m.routes {
597				target := r.Domain
598				if r.Mode == "tcp" {
599					target = fmt.Sprintf(":%d", r.PublicPort)
600				}
601				url := r.URL
602				if len(url) > 40 {
603					url = url[:39] + "…"
604				}
605				line := fmt.Sprintf("  %-6d %-6s %-30s %-8d %s", r.ID, r.Mode, target, r.Port, url)
606				if i == m.routeCursor {
607					line = selectedStyle.Render(fmt.Sprintf("  %-6d %-6s %-30s %-8d %-40s", r.ID, r.Mode, target, r.Port, url))
608				}
609				b.WriteString(line + "\n")
610			}
611		}
612	
613		b.WriteString("\n")
614		b.WriteString(helpStyle.Render("  a add  d delete  R refresh  esc/q back"))
615		b.WriteString("\n")
616	}
617	
618	func (m tuiModel) viewCreate(b *strings.Builder) {
619		b.WriteString(headerStyle.Render("  Create Sandbox") + "\n\n")
620		b.WriteString("  Name: " + m.createInput.View() + "\n")
621		b.WriteString("\n")
622		b.WriteString(helpStyle.Render("  enter confirm  esc cancel"))
623		b.WriteString("\n")
624	}
625	
626	func (m tuiModel) viewAddRoute(b *strings.Builder) {
627		b.WriteString(headerStyle.Render(fmt.Sprintf("  Add Route to %s", m.routeSandbox.Name)) + "\n\n")
628		b.WriteString("  Domain: " + m.routeInputs[0].View() + "\n")
629		b.WriteString("  Port:   " + m.routeInputs[1].View() + "\n")
630		b.WriteString("\n")
631		b.WriteString(helpStyle.Render("  tab next field  enter confirm  esc cancel"))
632		b.WriteString("\n")
633	}
634	
635	func (m tuiModel) viewConfirmDelete(b *strings.Builder) {
636		b.WriteString(errStyle.Render(fmt.Sprintf("  Destroy sandbox %q?", m.deleteTarget)) + "\n\n")
637		b.WriteString("  Press y to confirm, any other key to cancel.\n")
638	}
639	
640	// ---------- entry point ----------
641	
642	func runTUI() error {
643		client, err := api.NewClient()
644		if err != nil {
645			return err
646		}
647	
648		p := tea.NewProgram(newTUI(client), tea.WithAltScreen())
649		_, err = p.Run()
650		return err
651	}
