package cmd

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
	"time"

	"github.com/charmbracelet/bubbles/key"
	"github.com/charmbracelet/bubbles/spinner"
	"github.com/charmbracelet/bubbles/textinput"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
	"github.com/sandcastle/cli/api"
)

// ---------- styles ----------

var (
	titleStyle = lipgloss.NewStyle().
			Bold(true).
			Foreground(lipgloss.Color("214"))

	selectedStyle = lipgloss.NewStyle().
			Bold(true).
			Foreground(lipgloss.Color("229")).
			Background(lipgloss.Color("57"))

	statusRunning = lipgloss.NewStyle().Foreground(lipgloss.Color("42"))
	statusStopped = lipgloss.NewStyle().Foreground(lipgloss.Color("245"))

	helpStyle = lipgloss.NewStyle().Foreground(lipgloss.Color("241"))
	errStyle  = lipgloss.NewStyle().Foreground(lipgloss.Color("196"))
	okStyle   = lipgloss.NewStyle().Foreground(lipgloss.Color("42"))

	headerStyle = lipgloss.NewStyle().
			Bold(true).
			Foreground(lipgloss.Color("75"))

)

// ---------- views ----------

type tuiView int

const (
	viewSandboxes tuiView = iota
	viewRoutes
	viewCreateSandbox
	viewAddRoute
	viewConfirmDelete
)

// ---------- form field types ----------

type fieldKind int

const (
	fieldText fieldKind = iota
	fieldBool
)

type formField struct {
	label    string
	kind     fieldKind
	input    textinput.Model // for fieldText
	boolVal  bool            // for fieldBool
	defBool  bool            // default value (to show as dimmed when matching)
}

// ---------- messages ----------

type sandboxesLoadedMsg struct {
	sandboxes []api.Sandbox
	err       error
}

type routesLoadedMsg struct {
	routes []api.RouteResponse
	err    error
}

type snapshotsLoadedMsg struct {
	snapshots []api.Snapshot
	err       error
}

type actionDoneMsg struct {
	msg string
	err error
}

// ---------- model ----------

type tuiModel struct {
	client *api.Client

	view     tuiView
	cursor   int
	width    int
	height   int
	spinner  spinner.Model
	loading  bool
	feedback string
	feedErr  bool

	// sandbox list
	sandboxes []api.Sandbox

	// routes
	routeSandbox *api.Sandbox
	routes       []api.RouteResponse
	routeCursor  int

	// create sandbox form
	createFields   []formField
	createCursor   int
	snapshots      []api.Snapshot // cached for snapshot name completion

	// add route
	routeInputs    [2]textinput.Model // domain, port
	routeFocusIdx  int

	// confirm delete
	deleteTarget string
	deleteID     int
}

func makeTextInput(placeholder string, width int) textinput.Model {
	ti := textinput.New()
	ti.Placeholder = placeholder
	ti.CharLimit = 80
	ti.Width = width
	return ti
}

// Create form field indices — keep in sync with buildCreateFields.
const (
	cfName = iota
	cfImage
	cfSnapshot
	cfDocker
	cfVNC
	cfTailscale
	cfHome
	cfData
	cfSMB
	cfTemporary
	cfCount
)

func buildCreateFields() []formField {
	return []formField{
		{label: "Name", kind: fieldText, input: makeTextInput("leave empty for auto-generated name", 45)},
		{label: "Image", kind: fieldText, input: makeTextInput("ghcr.io/thieso2/sandcastle-sandbox:latest", 55)},
		{label: "Snapshot", kind: fieldText, input: makeTextInput("snapshot name to restore from", 45)},
		{label: "Docker", kind: fieldBool, boolVal: true, defBool: true},
		{label: "VNC", kind: fieldBool, boolVal: true, defBool: true},
		{label: "Tailscale", kind: fieldBool, boolVal: false, defBool: false},
		{label: "Home", kind: fieldBool, boolVal: false, defBool: false},
		{label: "Data path", kind: fieldText, input: makeTextInput("subpath or . for root (empty = none)", 45)},
		{label: "SMB", kind: fieldBool, boolVal: false, defBool: false},
		{label: "Temporary", kind: fieldBool, boolVal: false, defBool: false},
	}
}

func newTUI(client *api.Client) tuiModel {
	s := spinner.New()
	s.Spinner = spinner.Dot
	s.Style = lipgloss.NewStyle().Foreground(lipgloss.Color("214"))

	domainInput := makeTextInput("domain (e.g. app.example.com)", 40)
	portInput := makeTextInput("port (default 8080)", 10)
	portInput.CharLimit = 5

	return tuiModel{
		client:       client,
		spinner:      s,
		loading:      true,
		createFields: buildCreateFields(),
		routeInputs:  [2]textinput.Model{domainInput, portInput},
	}
}

func (m tuiModel) Init() tea.Cmd {
	return tea.Batch(m.spinner.Tick, loadSandboxes(m.client))
}

// ---------- commands ----------

func loadSandboxes(client *api.Client) tea.Cmd {
	return func() tea.Msg {
		sandboxes, err := client.ListSandboxes()
		return sandboxesLoadedMsg{sandboxes, err}
	}
}

func loadRoutes(client *api.Client, sandboxID int) tea.Cmd {
	return func() tea.Msg {
		routes, err := client.ListRoutes(sandboxID)
		return routesLoadedMsg{routes, err}
	}
}

func doAction(fn func() (string, error)) tea.Cmd {
	return func() tea.Msg {
		msg, err := fn()
		return actionDoneMsg{msg, err}
	}
}

// ---------- update ----------

func (m tuiModel) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		return m, nil

	case spinner.TickMsg:
		var cmd tea.Cmd
		m.spinner, cmd = m.spinner.Update(msg)
		return m, cmd

	case sandboxesLoadedMsg:
		m.loading = false
		if msg.err != nil {
			m.feedback = msg.err.Error()
			m.feedErr = true
			return m, nil
		}
		m.sandboxes = msg.sandboxes
		if m.cursor >= len(m.sandboxes) {
			m.cursor = max(0, len(m.sandboxes)-1)
		}
		return m, nil

	case routesLoadedMsg:
		m.loading = false
		if msg.err != nil {
			m.feedback = msg.err.Error()
			m.feedErr = true
			m.view = viewSandboxes
			return m, nil
		}
		m.routes = msg.routes
		m.routeCursor = 0
		return m, nil

	case actionDoneMsg:
		m.loading = false
		if msg.err != nil {
			m.feedback = msg.err.Error()
			m.feedErr = true
		} else {
			m.feedback = msg.msg
			m.feedErr = false
		}
		if m.view == viewConfirmDelete {
			m.view = viewSandboxes
		}
		// Reload context-appropriate data
		m.loading = true
		if m.view == viewRoutes && m.routeSandbox != nil {
			return m, tea.Batch(m.spinner.Tick, loadRoutes(m.client, m.routeSandbox.ID))
		}
		return m, tea.Batch(m.spinner.Tick, loadSandboxes(m.client))
	}

	switch m.view {
	case viewSandboxes:
		return m.updateSandboxes(msg)
	case viewRoutes:
		return m.updateRoutes(msg)
	case viewCreateSandbox:
		return m.updateCreate(msg)
	case viewAddRoute:
		return m.updateAddRoute(msg)
	case viewConfirmDelete:
		return m.updateConfirmDelete(msg)
	}
	return m, nil
}

func (m tuiModel) updateSandboxes(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		m.feedback = ""
		switch {
		case key.Matches(msg, key.NewBinding(key.WithKeys("q", "ctrl+c"))):
			return m, tea.Quit
		case key.Matches(msg, key.NewBinding(key.WithKeys("up", "k"))):
			if m.cursor > 0 {
				m.cursor--
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("down", "j"))):
			if m.cursor < len(m.sandboxes)-1 {
				m.cursor++
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("c"))):
			m.view = viewCreateSandbox
			m.createInput.SetValue("")
			m.createInput.Focus()
			return m, m.createInput.Cursor.BlinkCmd()
		case key.Matches(msg, key.NewBinding(key.WithKeys("r"))):
			if len(m.sandboxes) > 0 {
				m.loading = true
				m.feedback = ""
				sb := m.sandboxes[m.cursor]
				m.routeSandbox = &sb
				m.view = viewRoutes
				return m, tea.Batch(m.spinner.Tick, loadRoutes(m.client, sb.ID))
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("R"))):
			m.loading = true
			m.feedback = ""
			return m, tea.Batch(m.spinner.Tick, loadSandboxes(m.client))
		case key.Matches(msg, key.NewBinding(key.WithKeys("s"))):
			if len(m.sandboxes) > 0 {
				sb := m.sandboxes[m.cursor]
				if sb.Status == "stopped" {
					m.loading = true
					return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
						_, err := m.client.StartSandbox(sb.ID)
						return fmt.Sprintf("%q started", sb.Name), err
					}))
				}
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("x"))):
			if len(m.sandboxes) > 0 {
				sb := m.sandboxes[m.cursor]
				if sb.Status == "running" {
					m.loading = true
					return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
						_, err := m.client.StopSandbox(sb.ID)
						return fmt.Sprintf("%q stopped", sb.Name), err
					}))
				}
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("d"))):
			if len(m.sandboxes) > 0 {
				sb := m.sandboxes[m.cursor]
				m.deleteTarget = sb.Name
				m.deleteID = sb.ID
				m.view = viewConfirmDelete
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("enter"))):
			// connect — exit TUI, then reconnect via the CLI connect command
			if len(m.sandboxes) > 0 {
				sb := m.sandboxes[m.cursor]
				exe, _ := os.Executable()
				c := exec.Command(exe, "connect", sb.Name)
				c.Stdin = os.Stdin
				c.Stdout = os.Stdout
				c.Stderr = os.Stderr
				return m, tea.ExecProcess(c, func(err error) tea.Msg {
					return actionDoneMsg{"", err}
				})
			}
		}
	}
	return m, nil
}

func (m tuiModel) updateRoutes(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		m.feedback = ""
		switch {
		case key.Matches(msg, key.NewBinding(key.WithKeys("q", "esc"))):
			m.view = viewSandboxes
			m.routes = nil
			m.routeSandbox = nil
		case key.Matches(msg, key.NewBinding(key.WithKeys("ctrl+c"))):
			return m, tea.Quit
		case key.Matches(msg, key.NewBinding(key.WithKeys("up", "k"))):
			if m.routeCursor > 0 {
				m.routeCursor--
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("down", "j"))):
			if m.routeCursor < len(m.routes)-1 {
				m.routeCursor++
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("a"))):
			m.view = viewAddRoute
			m.routeFocusIdx = 0
			m.routeInputs[0].SetValue("")
			m.routeInputs[1].SetValue("")
			m.routeInputs[0].Focus()
			m.routeInputs[1].Blur()
			return m, m.routeInputs[0].Cursor.BlinkCmd()
		case key.Matches(msg, key.NewBinding(key.WithKeys("d"))):
			if len(m.routes) > 0 {
				r := m.routes[m.routeCursor]
				sbID := m.routeSandbox.ID
				m.loading = true
				return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
					err := m.client.RemoveRouteByID(sbID, r.ID)
					return fmt.Sprintf("Route #%d removed", r.ID), err
				}))
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("R"))):
			if m.routeSandbox != nil {
				m.loading = true
				return m, tea.Batch(m.spinner.Tick, loadRoutes(m.client, m.routeSandbox.ID))
			}
		}
	}
	return m, nil
}

func (m tuiModel) updateCreate(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		switch msg.Type {
		case tea.KeyEsc:
			m.view = viewSandboxes
			return m, nil
		case tea.KeyCtrlC:
			return m, tea.Quit
		case tea.KeyEnter:
			name := strings.TrimSpace(m.createInput.Value())
			if name == "" {
				name = fmt.Sprintf("temp-%d", time.Now().Unix())
			}
			m.view = viewSandboxes
			m.loading = true
			return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
				sb, err := m.client.CreateSandbox(api.CreateSandboxRequest{
					Name:          name,
					Image:         "ghcr.io/thieso2/sandcastle-sandbox:latest",
					VNCEnabled:    true,
					DockerEnabled: true,
				})
				if err != nil {
					return "", err
				}
				return fmt.Sprintf("%q created", sb.Name), nil
			}))
		}
	}
	var cmd tea.Cmd
	m.createInput, cmd = m.createInput.Update(msg)
	return m, cmd
}

func (m tuiModel) updateAddRoute(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		switch msg.Type {
		case tea.KeyEsc:
			m.view = viewRoutes
			return m, nil
		case tea.KeyCtrlC:
			return m, tea.Quit
		case tea.KeyTab, tea.KeyShiftTab:
			m.routeFocusIdx = (m.routeFocusIdx + 1) % 2
			for i := range m.routeInputs {
				if i == m.routeFocusIdx {
					m.routeInputs[i].Focus()
				} else {
					m.routeInputs[i].Blur()
				}
			}
			return m, m.routeInputs[m.routeFocusIdx].Cursor.BlinkCmd()
		case tea.KeyEnter:
			domain := strings.TrimSpace(m.routeInputs[0].Value())
			portStr := strings.TrimSpace(m.routeInputs[1].Value())
			if domain == "" {
				m.feedback = "domain is required"
				m.feedErr = true
				return m, nil
			}
			port := 8080
			if portStr != "" {
				n := 0
				for _, ch := range portStr {
					if ch < '0' || ch > '9' {
						m.feedback = "invalid port"
						m.feedErr = true
						return m, nil
					}
					n = n*10 + int(ch-'0')
				}
				port = n
			}
			sbID := m.routeSandbox.ID
			m.view = viewRoutes
			m.loading = true
			return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
				r, err := m.client.AddRoute(sbID, api.RouteRequest{
					Domain: domain,
					Port:   port,
					Mode:   "http",
				})
				if err != nil {
					return "", err
				}
				return fmt.Sprintf("Route added: %s → :%d", r.Domain, r.Port), nil
			}))
		}
	}

	var cmd tea.Cmd
	m.routeInputs[m.routeFocusIdx], cmd = m.routeInputs[m.routeFocusIdx].Update(msg)
	return m, cmd
}

func (m tuiModel) updateConfirmDelete(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		switch {
		case key.Matches(msg, key.NewBinding(key.WithKeys("y", "Y"))):
			id := m.deleteID
			name := m.deleteTarget
			m.loading = true
			return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
				err := m.client.DestroySandbox(id)
				return fmt.Sprintf("%q destroyed", name), err
			}))
		default:
			m.view = viewSandboxes
			m.feedback = "cancelled"
			m.feedErr = false
		}
	}
	return m, nil
}

// ---------- view ----------

func (m tuiModel) View() string {
	var b strings.Builder

	title := titleStyle.Render("  Sandcastle")
	if m.client.ServerAlias != "" {
		title += helpStyle.Render(fmt.Sprintf("  %s", m.client.ServerAlias))
	}
	b.WriteString(title + "\n\n")

	switch m.view {
	case viewSandboxes:
		m.viewSandboxes(&b)
	case viewRoutes:
		m.viewRoutes(&b)
	case viewCreateSandbox:
		m.viewCreate(&b)
	case viewAddRoute:
		m.viewAddRoute(&b)
	case viewConfirmDelete:
		m.viewConfirmDelete(&b)
	}

	// Feedback
	if m.feedback != "" {
		b.WriteString("\n")
		if m.feedErr {
			b.WriteString(errStyle.Render("  " + m.feedback))
		} else {
			b.WriteString(okStyle.Render("  " + m.feedback))
		}
		b.WriteString("\n")
	}

	return b.String()
}

func (m tuiModel) viewSandboxes(b *strings.Builder) {
	if m.loading && len(m.sandboxes) == 0 {
		b.WriteString("  " + m.spinner.View() + " Loading sandboxes...\n")
		b.WriteString("\n" + helpStyle.Render("  q quit"))
		return
	}

	if len(m.sandboxes) == 0 {
		b.WriteString("  No sandboxes. Press c to create one.\n")
	} else {
		// Header
		b.WriteString(headerStyle.Render(fmt.Sprintf("  %-22s %-10s %-18s %s", "NAME", "STATUS", "CREATED", "ROUTE")) + "\n")

		for i, sb := range m.sandboxes {
			name := sb.Name
			if sb.Temporary {
				name += " ~"
			}
			if len(name) > 22 {
				name = name[:21] + "…"
			}

			st := statusStopped.Render(sb.Status)
			if sb.Status == "running" {
				st = statusRunning.Render(sb.Status)
			}

			created := sb.CreatedAt.Local().Format("Jan 02 15:04")

			route := ""
			if len(sb.Routes) > 0 {
				parts := make([]string, 0, len(sb.Routes))
				for _, r := range sb.Routes {
					if r.Mode == "tcp" {
						parts = append(parts, fmt.Sprintf("tcp/:%d", r.PublicPort))
					} else {
						parts = append(parts, r.Domain)
					}
				}
				route = strings.Join(parts, ", ")
				if len(route) > 30 {
					route = route[:29] + "…"
				}
			}

			line := fmt.Sprintf("  %-22s %-10s %-18s %s", name, st, created, route)
			if i == m.cursor {
				// Re-render with selection styling — pad to width
				padded := fmt.Sprintf("  %-22s %-20s %-18s %-30s", name, sb.Status, created, route)
				line = selectedStyle.Render(padded)
			}
			b.WriteString(line + "\n")
		}
	}

	if m.loading {
		b.WriteString("\n  " + m.spinner.View() + "\n")
	}

	b.WriteString("\n")
	b.WriteString(helpStyle.Render("  enter connect  c create  s start  x stop  d destroy  r routes  R refresh  q quit"))
	b.WriteString("\n")
}

func (m tuiModel) viewRoutes(b *strings.Builder) {
	b.WriteString(headerStyle.Render(fmt.Sprintf("  Routes for %s", m.routeSandbox.Name)) + "\n\n")

	if m.loading {
		b.WriteString("  " + m.spinner.View() + " Loading routes...\n")
		b.WriteString("\n" + helpStyle.Render("  esc back  q quit"))
		return
	}

	if len(m.routes) == 0 {
		b.WriteString("  No routes. Press a to add one.\n")
	} else {
		b.WriteString(headerStyle.Render(fmt.Sprintf("  %-6s %-6s %-30s %-8s %s", "ID", "MODE", "DOMAIN / PUBLIC PORT", "PORT", "URL")) + "\n")
		for i, r := range m.routes {
			target := r.Domain
			if r.Mode == "tcp" {
				target = fmt.Sprintf(":%d", r.PublicPort)
			}
			url := r.URL
			if len(url) > 40 {
				url = url[:39] + "…"
			}
			line := fmt.Sprintf("  %-6d %-6s %-30s %-8d %s", r.ID, r.Mode, target, r.Port, url)
			if i == m.routeCursor {
				line = selectedStyle.Render(fmt.Sprintf("  %-6d %-6s %-30s %-8d %-40s", r.ID, r.Mode, target, r.Port, url))
			}
			b.WriteString(line + "\n")
		}
	}

	b.WriteString("\n")
	b.WriteString(helpStyle.Render("  a add  d delete  R refresh  esc/q back"))
	b.WriteString("\n")
}

func (m tuiModel) viewCreate(b *strings.Builder) {
	b.WriteString(headerStyle.Render("  Create Sandbox") + "\n\n")
	b.WriteString("  Name: " + m.createInput.View() + "\n")
	b.WriteString("\n")
	b.WriteString(helpStyle.Render("  enter confirm  esc cancel"))
	b.WriteString("\n")
}

func (m tuiModel) viewAddRoute(b *strings.Builder) {
	b.WriteString(headerStyle.Render(fmt.Sprintf("  Add Route to %s", m.routeSandbox.Name)) + "\n\n")
	b.WriteString("  Domain: " + m.routeInputs[0].View() + "\n")
	b.WriteString("  Port:   " + m.routeInputs[1].View() + "\n")
	b.WriteString("\n")
	b.WriteString(helpStyle.Render("  tab next field  enter confirm  esc cancel"))
	b.WriteString("\n")
}

func (m tuiModel) viewConfirmDelete(b *strings.Builder) {
	b.WriteString(errStyle.Render(fmt.Sprintf("  Destroy sandbox %q?", m.deleteTarget)) + "\n\n")
	b.WriteString("  Press y to confirm, any other key to cancel.\n")
}

// ---------- entry point ----------

func runTUI() error {
	client, err := api.NewClient()
	if err != nil {
		return err
	}

	p := tea.NewProgram(newTUI(client), tea.WithAltScreen())
	_, err = p.Run()
	return err
}

package cmd

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
	"time"

	"github.com/charmbracelet/bubbles/key"
	"github.com/charmbracelet/bubbles/spinner"
	"github.com/charmbracelet/bubbles/textinput"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
	"github.com/sandcastle/cli/api"
)

// ---------- styles ----------

var (
	titleStyle = lipgloss.NewStyle().
			Bold(true).
			Foreground(lipgloss.Color("214"))

	selectedStyle = lipgloss.NewStyle().
			Bold(true).
			Foreground(lipgloss.Color("229")).
			Background(lipgloss.Color("57"))

	statusRunning = lipgloss.NewStyle().Foreground(lipgloss.Color("42"))
	statusStopped = lipgloss.NewStyle().Foreground(lipgloss.Color("245"))

	helpStyle = lipgloss.NewStyle().Foreground(lipgloss.Color("241"))
	errStyle  = lipgloss.NewStyle().Foreground(lipgloss.Color("196"))
	okStyle   = lipgloss.NewStyle().Foreground(lipgloss.Color("42"))

	headerStyle = lipgloss.NewStyle().
			Bold(true).
			Foreground(lipgloss.Color("75"))

)

// ---------- views ----------

type tuiView int

const (
	viewSandboxes tuiView = iota
	viewRoutes
	viewCreateSandbox
	viewAddRoute
	viewConfirmDelete
)

// ---------- form field types ----------

type fieldKind int

const (
	fieldText fieldKind = iota
	fieldBool
)

type formField struct {
	label    string
	kind     fieldKind
	input    textinput.Model // for fieldText
	boolVal  bool            // for fieldBool
	defBool  bool            // default value (to show as dimmed when matching)
}

// ---------- messages ----------

type sandboxesLoadedMsg struct {
	sandboxes []api.Sandbox
	err       error
}

type routesLoadedMsg struct {
	routes []api.RouteResponse
	err    error
}

type snapshotsLoadedMsg struct {
	snapshots []api.Snapshot
	err       error
}

type actionDoneMsg struct {
	msg string
	err error
}

// ---------- model ----------

type tuiModel struct {
	client *api.Client

	view     tuiView
	cursor   int
	width    int
	height   int
	spinner  spinner.Model
	loading  bool
	feedback string
	feedErr  bool

	// sandbox list
	sandboxes []api.Sandbox

	// routes
	routeSandbox *api.Sandbox
	routes       []api.RouteResponse
	routeCursor  int

	// create sandbox form
	createFields   []formField
	createCursor   int
	snapshots      []api.Snapshot // cached for snapshot name completion

	// add route
	routeInputs    [2]textinput.Model // domain, port
	routeFocusIdx  int

	// confirm delete
	deleteTarget string
	deleteID     int
}

func makeTextInput(placeholder string, width int) textinput.Model {
	ti := textinput.New()
	ti.Placeholder = placeholder
	ti.CharLimit = 80
	ti.Width = width
	return ti
}

// Create form field indices — keep in sync with buildCreateFields.
const (
	cfName = iota
	cfImage
	cfSnapshot
	cfDocker
	cfVNC
	cfTailscale
	cfHome
	cfData
	cfSMB
	cfTemporary
	cfCount
)

func buildCreateFields() []formField {
	return []formField{
		{label: "Name", kind: fieldText, input: makeTextInput("leave empty for auto-generated name", 45)},
		{label: "Image", kind: fieldText, input: makeTextInput("ghcr.io/thieso2/sandcastle-sandbox:latest", 55)},
		{label: "Snapshot", kind: fieldText, input: makeTextInput("snapshot name to restore from", 45)},
		{label: "Docker", kind: fieldBool, boolVal: true, defBool: true},
		{label: "VNC", kind: fieldBool, boolVal: true, defBool: true},
		{label: "Tailscale", kind: fieldBool, boolVal: false, defBool: false},
		{label: "Home", kind: fieldBool, boolVal: false, defBool: false},
		{label: "Data path", kind: fieldText, input: makeTextInput("subpath or . for root (empty = none)", 45)},
		{label: "SMB", kind: fieldBool, boolVal: false, defBool: false},
		{label: "Temporary", kind: fieldBool, boolVal: false, defBool: false},
	}
}

func newTUI(client *api.Client) tuiModel {
	s := spinner.New()
	s.Spinner = spinner.Dot
	s.Style = lipgloss.NewStyle().Foreground(lipgloss.Color("214"))

	domainInput := makeTextInput("domain (e.g. app.example.com)", 40)
	portInput := makeTextInput("port (default 8080)", 10)
	portInput.CharLimit = 5

	return tuiModel{
		client:       client,
		spinner:      s,
		loading:      true,
		createFields: buildCreateFields(),
		routeInputs:  [2]textinput.Model{domainInput, portInput},
	}
}

func (m tuiModel) Init() tea.Cmd {
	return tea.Batch(m.spinner.Tick, loadSandboxes(m.client))
}

// ---------- commands ----------

func loadSandboxes(client *api.Client) tea.Cmd {
	return func() tea.Msg {
		sandboxes, err := client.ListSandboxes()
		return sandboxesLoadedMsg{sandboxes, err}
	}
}

func loadRoutes(client *api.Client, sandboxID int) tea.Cmd {
	return func() tea.Msg {
		routes, err := client.ListRoutes(sandboxID)
		return routesLoadedMsg{routes, err}
	}
}

func loadSnapshots(client *api.Client) tea.Cmd {
	return func() tea.Msg {
		snapshots, err := client.ListSnapshots()
		return snapshotsLoadedMsg{snapshots, err}
	}
}

func doAction(fn func() (string, error)) tea.Cmd {
	return func() tea.Msg {
		msg, err := fn()
		return actionDoneMsg{msg, err}
	}
}

// ---------- update ----------

func (m tuiModel) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		return m, nil

	case spinner.TickMsg:
		var cmd tea.Cmd
		m.spinner, cmd = m.spinner.Update(msg)
		return m, cmd

	case sandboxesLoadedMsg:
		m.loading = false
		if msg.err != nil {
			m.feedback = msg.err.Error()
			m.feedErr = true
			return m, nil
		}
		m.sandboxes = msg.sandboxes
		if m.cursor >= len(m.sandboxes) {
			m.cursor = max(0, len(m.sandboxes)-1)
		}
		return m, nil

	case routesLoadedMsg:
		m.loading = false
		if msg.err != nil {
			m.feedback = msg.err.Error()
			m.feedErr = true
			m.view = viewSandboxes
			return m, nil
		}
		m.routes = msg.routes
		m.routeCursor = 0
		return m, nil

	case actionDoneMsg:
		m.loading = false
		if msg.err != nil {
			m.feedback = msg.err.Error()
			m.feedErr = true
		} else {
			m.feedback = msg.msg
			m.feedErr = false
		}
		if m.view == viewConfirmDelete {
			m.view = viewSandboxes
		}
		// Reload context-appropriate data
		m.loading = true
		if m.view == viewRoutes && m.routeSandbox != nil {
			return m, tea.Batch(m.spinner.Tick, loadRoutes(m.client, m.routeSandbox.ID))
		}
		return m, tea.Batch(m.spinner.Tick, loadSandboxes(m.client))
	}

	switch m.view {
	case viewSandboxes:
		return m.updateSandboxes(msg)
	case viewRoutes:
		return m.updateRoutes(msg)
	case viewCreateSandbox:
		return m.updateCreate(msg)
	case viewAddRoute:
		return m.updateAddRoute(msg)
	case viewConfirmDelete:
		return m.updateConfirmDelete(msg)
	}
	return m, nil
}

func (m tuiModel) updateSandboxes(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		m.feedback = ""
		switch {
		case key.Matches(msg, key.NewBinding(key.WithKeys("q", "ctrl+c"))):
			return m, tea.Quit
		case key.Matches(msg, key.NewBinding(key.WithKeys("up", "k"))):
			if m.cursor > 0 {
				m.cursor--
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("down", "j"))):
			if m.cursor < len(m.sandboxes)-1 {
				m.cursor++
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("c"))):
			m.view = viewCreateSandbox
			m.createInput.SetValue("")
			m.createInput.Focus()
			return m, m.createInput.Cursor.BlinkCmd()
		case key.Matches(msg, key.NewBinding(key.WithKeys("r"))):
			if len(m.sandboxes) > 0 {
				m.loading = true
				m.feedback = ""
				sb := m.sandboxes[m.cursor]
				m.routeSandbox = &sb
				m.view = viewRoutes
				return m, tea.Batch(m.spinner.Tick, loadRoutes(m.client, sb.ID))
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("R"))):
			m.loading = true
			m.feedback = ""
			return m, tea.Batch(m.spinner.Tick, loadSandboxes(m.client))
		case key.Matches(msg, key.NewBinding(key.WithKeys("s"))):
			if len(m.sandboxes) > 0 {
				sb := m.sandboxes[m.cursor]
				if sb.Status == "stopped" {
					m.loading = true
					return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
						_, err := m.client.StartSandbox(sb.ID)
						return fmt.Sprintf("%q started", sb.Name), err
					}))
				}
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("x"))):
			if len(m.sandboxes) > 0 {
				sb := m.sandboxes[m.cursor]
				if sb.Status == "running" {
					m.loading = true
					return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
						_, err := m.client.StopSandbox(sb.ID)
						return fmt.Sprintf("%q stopped", sb.Name), err
					}))
				}
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("d"))):
			if len(m.sandboxes) > 0 {
				sb := m.sandboxes[m.cursor]
				m.deleteTarget = sb.Name
				m.deleteID = sb.ID
				m.view = viewConfirmDelete
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("enter"))):
			// connect — exit TUI, then reconnect via the CLI connect command
			if len(m.sandboxes) > 0 {
				sb := m.sandboxes[m.cursor]
				exe, _ := os.Executable()
				c := exec.Command(exe, "connect", sb.Name)
				c.Stdin = os.Stdin
				c.Stdout = os.Stdout
				c.Stderr = os.Stderr
				return m, tea.ExecProcess(c, func(err error) tea.Msg {
					return actionDoneMsg{"", err}
				})
			}
		}
	}
	return m, nil
}

func (m tuiModel) updateRoutes(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		m.feedback = ""
		switch {
		case key.Matches(msg, key.NewBinding(key.WithKeys("q", "esc"))):
			m.view = viewSandboxes
			m.routes = nil
			m.routeSandbox = nil
		case key.Matches(msg, key.NewBinding(key.WithKeys("ctrl+c"))):
			return m, tea.Quit
		case key.Matches(msg, key.NewBinding(key.WithKeys("up", "k"))):
			if m.routeCursor > 0 {
				m.routeCursor--
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("down", "j"))):
			if m.routeCursor < len(m.routes)-1 {
				m.routeCursor++
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("a"))):
			m.view = viewAddRoute
			m.routeFocusIdx = 0
			m.routeInputs[0].SetValue("")
			m.routeInputs[1].SetValue("")
			m.routeInputs[0].Focus()
			m.routeInputs[1].Blur()
			return m, m.routeInputs[0].Cursor.BlinkCmd()
		case key.Matches(msg, key.NewBinding(key.WithKeys("d"))):
			if len(m.routes) > 0 {
				r := m.routes[m.routeCursor]
				sbID := m.routeSandbox.ID
				m.loading = true
				return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
					err := m.client.RemoveRouteByID(sbID, r.ID)
					return fmt.Sprintf("Route #%d removed", r.ID), err
				}))
			}
		case key.Matches(msg, key.NewBinding(key.WithKeys("R"))):
			if m.routeSandbox != nil {
				m.loading = true
				return m, tea.Batch(m.spinner.Tick, loadRoutes(m.client, m.routeSandbox.ID))
			}
		}
	}
	return m, nil
}

func (m tuiModel) updateCreate(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		switch msg.Type {
		case tea.KeyEsc:
			m.view = viewSandboxes
			return m, nil
		case tea.KeyCtrlC:
			return m, tea.Quit
		case tea.KeyEnter:
			name := strings.TrimSpace(m.createInput.Value())
			if name == "" {
				name = fmt.Sprintf("temp-%d", time.Now().Unix())
			}
			m.view = viewSandboxes
			m.loading = true
			return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
				sb, err := m.client.CreateSandbox(api.CreateSandboxRequest{
					Name:          name,
					Image:         "ghcr.io/thieso2/sandcastle-sandbox:latest",
					VNCEnabled:    true,
					DockerEnabled: true,
				})
				if err != nil {
					return "", err
				}
				return fmt.Sprintf("%q created", sb.Name), nil
			}))
		}
	}
	var cmd tea.Cmd
	m.createInput, cmd = m.createInput.Update(msg)
	return m, cmd
}

func (m tuiModel) updateAddRoute(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		switch msg.Type {
		case tea.KeyEsc:
			m.view = viewRoutes
			return m, nil
		case tea.KeyCtrlC:
			return m, tea.Quit
		case tea.KeyTab, tea.KeyShiftTab:
			m.routeFocusIdx = (m.routeFocusIdx + 1) % 2
			for i := range m.routeInputs {
				if i == m.routeFocusIdx {
					m.routeInputs[i].Focus()
				} else {
					m.routeInputs[i].Blur()
				}
			}
			return m, m.routeInputs[m.routeFocusIdx].Cursor.BlinkCmd()
		case tea.KeyEnter:
			domain := strings.TrimSpace(m.routeInputs[0].Value())
			portStr := strings.TrimSpace(m.routeInputs[1].Value())
			if domain == "" {
				m.feedback = "domain is required"
				m.feedErr = true
				return m, nil
			}
			port := 8080
			if portStr != "" {
				n := 0
				for _, ch := range portStr {
					if ch < '0' || ch > '9' {
						m.feedback = "invalid port"
						m.feedErr = true
						return m, nil
					}
					n = n*10 + int(ch-'0')
				}
				port = n
			}
			sbID := m.routeSandbox.ID
			m.view = viewRoutes
			m.loading = true
			return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
				r, err := m.client.AddRoute(sbID, api.RouteRequest{
					Domain: domain,
					Port:   port,
					Mode:   "http",
				})
				if err != nil {
					return "", err
				}
				return fmt.Sprintf("Route added: %s → :%d", r.Domain, r.Port), nil
			}))
		}
	}

	var cmd tea.Cmd
	m.routeInputs[m.routeFocusIdx], cmd = m.routeInputs[m.routeFocusIdx].Update(msg)
	return m, cmd
}

func (m tuiModel) updateConfirmDelete(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		switch {
		case key.Matches(msg, key.NewBinding(key.WithKeys("y", "Y"))):
			id := m.deleteID
			name := m.deleteTarget
			m.loading = true
			return m, tea.Batch(m.spinner.Tick, doAction(func() (string, error) {
				err := m.client.DestroySandbox(id)
				return fmt.Sprintf("%q destroyed", name), err
			}))
		default:
			m.view = viewSandboxes
			m.feedback = "cancelled"
			m.feedErr = false
		}
	}
	return m, nil
}

// ---------- view ----------

func (m tuiModel) View() string {
	var b strings.Builder

	title := titleStyle.Render("  Sandcastle")
	if m.client.ServerAlias != "" {
		title += helpStyle.Render(fmt.Sprintf("  %s", m.client.ServerAlias))
	}
	b.WriteString(title + "\n\n")

	switch m.view {
	case viewSandboxes:
		m.viewSandboxes(&b)
	case viewRoutes:
		m.viewRoutes(&b)
	case viewCreateSandbox:
		m.viewCreate(&b)
	case viewAddRoute:
		m.viewAddRoute(&b)
	case viewConfirmDelete:
		m.viewConfirmDelete(&b)
	}

	// Feedback
	if m.feedback != "" {
		b.WriteString("\n")
		if m.feedErr {
			b.WriteString(errStyle.Render("  " + m.feedback))
		} else {
			b.WriteString(okStyle.Render("  " + m.feedback))
		}
		b.WriteString("\n")
	}

	return b.String()
}

func (m tuiModel) viewSandboxes(b *strings.Builder) {
	if m.loading && len(m.sandboxes) == 0 {
		b.WriteString("  " + m.spinner.View() + " Loading sandboxes...\n")
		b.WriteString("\n" + helpStyle.Render("  q quit"))
		return
	}

	if len(m.sandboxes) == 0 {
		b.WriteString("  No sandboxes. Press c to create one.\n")
	} else {
		// Header
		b.WriteString(headerStyle.Render(fmt.Sprintf("  %-22s %-10s %-18s %s", "NAME", "STATUS", "CREATED", "ROUTE")) + "\n")

		for i, sb := range m.sandboxes {
			name := sb.Name
			if sb.Temporary {
				name += " ~"
			}
			if len(name) > 22 {
				name = name[:21] + "…"
			}

			st := statusStopped.Render(sb.Status)
			if sb.Status == "running" {
				st = statusRunning.Render(sb.Status)
			}

			created := sb.CreatedAt.Local().Format("Jan 02 15:04")

			route := ""
			if len(sb.Routes) > 0 {
				parts := make([]string, 0, len(sb.Routes))
				for _, r := range sb.Routes {
					if r.Mode == "tcp" {
						parts = append(parts, fmt.Sprintf("tcp/:%d", r.PublicPort))
					} else {
						parts = append(parts, r.Domain)
					}
				}
				route = strings.Join(parts, ", ")
				if len(route) > 30 {
					route = route[:29] + "…"
				}
			}

			line := fmt.Sprintf("  %-22s %-10s %-18s %s", name, st, created, route)
			if i == m.cursor {
				// Re-render with selection styling — pad to width
				padded := fmt.Sprintf("  %-22s %-20s %-18s %-30s", name, sb.Status, created, route)
				line = selectedStyle.Render(padded)
			}
			b.WriteString(line + "\n")
		}
	}

	if m.loading {
		b.WriteString("\n  " + m.spinner.View() + "\n")
	}

	b.WriteString("\n")
	b.WriteString(helpStyle.Render("  enter connect  c create  s start  x stop  d destroy  r routes  R refresh  q quit"))
	b.WriteString("\n")
}

func (m tuiModel) viewRoutes(b *strings.Builder) {
	b.WriteString(headerStyle.Render(fmt.Sprintf("  Routes for %s", m.routeSandbox.Name)) + "\n\n")

	if m.loading {
		b.WriteString("  " + m.spinner.View() + " Loading routes...\n")
		b.WriteString("\n" + helpStyle.Render("  esc back  q quit"))
		return
	}

	if len(m.routes) == 0 {
		b.WriteString("  No routes. Press a to add one.\n")
	} else {
		b.WriteString(headerStyle.Render(fmt.Sprintf("  %-6s %-6s %-30s %-8s %s", "ID", "MODE", "DOMAIN / PUBLIC PORT", "PORT", "URL")) + "\n")
		for i, r := range m.routes {
			target := r.Domain
			if r.Mode == "tcp" {
				target = fmt.Sprintf(":%d", r.PublicPort)
			}
			url := r.URL
			if len(url) > 40 {
				url = url[:39] + "…"
			}
			line := fmt.Sprintf("  %-6d %-6s %-30s %-8d %s", r.ID, r.Mode, target, r.Port, url)
			if i == m.routeCursor {
				line = selectedStyle.Render(fmt.Sprintf("  %-6d %-6s %-30s %-8d %-40s", r.ID, r.Mode, target, r.Port, url))
			}
			b.WriteString(line + "\n")
		}
	}

	b.WriteString("\n")
	b.WriteString(helpStyle.Render("  a add  d delete  R refresh  esc/q back"))
	b.WriteString("\n")
}

func (m tuiModel) viewCreate(b *strings.Builder) {
	b.WriteString(headerStyle.Render("  Create Sandbox") + "\n\n")
	b.WriteString("  Name: " + m.createInput.View() + "\n")
	b.WriteString("\n")
	b.WriteString(helpStyle.Render("  enter confirm  esc cancel"))
	b.WriteString("\n")
}

func (m tuiModel) viewAddRoute(b *strings.Builder) {
	b.WriteString(headerStyle.Render(fmt.Sprintf("  Add Route to %s", m.routeSandbox.Name)) + "\n\n")
	b.WriteString("  Domain: " + m.routeInputs[0].View() + "\n")
	b.WriteString("  Port:   " + m.routeInputs[1].View() + "\n")
	b.WriteString("\n")
	b.WriteString(helpStyle.Render("  tab next field  enter confirm  esc cancel"))
	b.WriteString("\n")
}

func (m tuiModel) viewConfirmDelete(b *strings.Builder) {
	b.WriteString(errStyle.Render(fmt.Sprintf("  Destroy sandbox %q?", m.deleteTarget)) + "\n\n")
	b.WriteString("  Press y to confirm, any other key to cancel.\n")
}

// ---------- entry point ----------

func runTUI() error {
	client, err := api.NewClient()
	if err != nil {
		return err
	}

	p := tea.NewProgram(newTUI(client), tea.WithAltScreen())
	_, err = p.Run()
	return err
}

