		m.feedback = msg.err.Error()
		m.feedErr = true
		m.loginPolling = false
		m.view = viewServers
		return m, nil
	}
	if msg.pending {
		// Keep polling
		return m, pollDeviceToken(m.loginClient, m.loginDeviceCode.DeviceCode)
	}
