	err    error
}

type snapshotsLoadedMsg struct {
	snapshots []api.Snapshot
	err       error
}

type actionDoneMsg struct {
	msg string
	err error
}

type deviceCodeMsg struct {
	code *api.DeviceCodeResponse
	err  error
}

type deviceTokenMsg struct {
	token   string
	pending bool
	err     error
}

// ---------- model ----------

type tuiModel struct {
	client *api.Client

	view     tuiView
	cursor   int
	width    int
	height   int
	spinner  spinner.Model
	loading  bool
	feedback string
	feedErr  bool

	// sandbox list
	sandboxes []api.Sandbox

	// routes
	routeSandbox *api.Sandbox
	routes       []api.RouteResponse
	routeCursor  int

	// create sandbox form
	createFields   []formField
	createCursor   int
	snapshots      []api.Snapshot // cached for snapshot name completion

	// add route
	routeInputs    [2]textinput.Model // domain, port
	routeFocusIdx  int

	// confirm delete
	deleteTarget string
