var (
	serverActiveStyle = lipgloss.NewStyle().
				Bold(true).
				Foreground(lipgloss.Color("42"))

	serverAuthStyle = lipgloss.NewStyle().
			Foreground(lipgloss.Color("245"))

	codeStyle = lipgloss.NewStyle().
