				Foreground(lipgloss.Color("214"))

	checkOn  = lipgloss.NewStyle().Foreground(lipgloss.Color("42")).Render("[x]")
	checkOff = lipgloss.NewStyle().Foreground(lipgloss.Color("245")).Render("[ ]")
